import numpy as np
from bisect import insort

class IncrementalAUC:
    def __init__(self):
        # Maintain sorted predictions and their labels
        # ponytail: O(n) insert, switch to balanced BST for O(log n)
        self.sorted_preds = []  # (score, label)
        self.n_pos = 0
        self.n_neg = 0

    def update(self, score, label):
        """Add one prediction. O(n) insert."""
        insort(self.sorted_preds, (score, label))
        if label == 1:
            self.n_pos += 1
        else:
            self.n_neg += 1

    def auc(self):
        """Compute AUC using Mann-Whitney U statistic."""
        if self.n_pos == 0 or self.n_neg == 0:
            return 0.5
        # Sum of ranks of positive examples
        rank_sum = 0
        for i, (_, label) in enumerate(self.sorted_preds):
            if label == 1:
                rank_sum += (i + 1)  # 1-indexed ranks
        # Mann-Whitney U statistic
        u = rank_sum - (self.n_pos * (self.n_pos + 1) / 2)
        return u / (self.n_pos * self.n_neg)

    def auc_fast(self):
        """Faster: pre-computed rank sum update (not shown for brevity).
        Real streaming: use a Fenwick tree for O(log n) insert + O(log n) rank sum.
        """
        return self.auc()

# For real production, use threshold-based approximation:
def streaming_auc_approx(thresholds=100):
    """Trapezoidal AUC from FPR/TPR histogram.
    Trade-off: ±0.001 accuracy vs O(1) memory.
    """
    tpr = np.zeros(thresholds)
    fpr = np.zeros(thresholds)
    pos_total = 1e-8; neg_total = 1e-8
    def update(score, label):
        nonlocal pos_total, neg_total
        bucket = min(int(score * thresholds), thresholds - 1)
        if label == 1:
            tpr[bucket] += 1; pos_total += 1
        else:
            fpr[bucket] += 1; neg_total += 1
    def compute():
        tpr_cum = np.cumsum(tpr[::-1])[::-1] / pos_total
        fpr_cum = np.cumsum(fpr[::-1])[::-1] / neg_total
        return -np.trapz(tpr_cum, fpr_cum)
    return update, compute

from collections import deque

class SimpleMovingAverage:
    """O(1) per element, O(W) memory."""
    def __init__(self, window):
        self.window = window
        self.buffer = deque(maxlen=window)
        self.sum = 0.0

    def add(self, x):
        if len(self.buffer) == self.window:
            self.sum -= self.buffer[0]  # pop oldest
        self.buffer.append(x)
        self.sum += x
        return self.sum / len(self.buffer)

    @property
    def value(self):
        return self.sum / len(self.buffer) if self.buffer else 0.0


class ExponentialMovingAverage:
    """O(1) per element, O(1) memory.
    α = 2 / (W + 1) gives equivalent center of mass as SMA(W).
    """
    def __init__(self, alpha=0.1):
        self.alpha = alpha
        self.ema = None

    def add(self, x):
        if self.ema is None:
            self.ema = x
        else:
            self.ema = self.alpha * x + (1 - self.alpha) * self.ema
        return self.ema

    @property
    def value(self):
        return self.ema if self.ema is not None else 0.0


class BiasCorrectedEMA:
    """EMA with bias correction for the initial warm-up period.
    Used in Adam optimizer (Kingma & Ba 2015).
    """
    def __init__(self, alpha=0.1):
        self.alpha = alpha
        self.ema = 0.0
        self.steps = 0

    def add(self, x):
        self.steps += 1
        self.ema = self.alpha * x + (1 - self.alpha) * self.ema
        # Bias correction: divide by (1 - α^t)
        return self.ema / (1 - self.alpha ** self.steps)

