from collections import deque
import time

class SlidingWindowMetrics:
    """Track precision, recall, F1 over a sliding time window.
    O(1) update using running counts, O(W) memory where W = window * rate.
    """
    def __init__(self, window_seconds=3600):
        self.window = window_seconds
        self.events = deque()  # (timestamp, pred, label)
        self.tp = 0; self.fp = 0; self.fn = 0; self.tn = 0

    def _trim(self):
        cutoff = time.time() - self.window
        while self.events and self.events[0][0] < cutoff:
            _, pred, label = self.events.popleft()
            if pred == 1 and label == 1:
                self.tp -= 1
            elif pred == 1 and label == 0:
                self.fp -= 1
            elif pred == 0 and label == 1:
                self.fn -= 1
            else:
                self.tn -= 1

    def update(self, prediction, label):
        self._trim()
        self.events.append((time.time(), prediction, label))
        if prediction == 1 and label == 1:
            self.tp += 1
        elif prediction == 1 and label == 0:
            self.fp += 1
        elif prediction == 0 and label == 1:
            self.fn += 1
        else:
            self.tn += 1

    @property
    def precision(self):
        return self.tp / (self.tp + self.fp + 1e-8)

    @property
    def recall(self):
        return self.tp / (self.tp + self.fn + 1e-8)

    @property
    def f1(self):
        p = self.precision; r = self.recall
        return 2 * p * r / (p + r + 1e-8)

    @property
    def accuracy(self):
        return (self.tp + self.tn) / (len(self.events) + 1e-8)


class EMAWindowMetrics:
    """Memory-free sliding metrics using EMA.
    O(1) memory, O(1) update — for high-throughput production.
    """
    def __init__(self, alpha=0.001):
        self.alpha = alpha
        self.tp = 0.0; self.fp = 0.0; self.fn = 0.0

    def update(self, pred, label):
        # EMA-update confusion matrix
        decay = 1 - self.alpha
        self.tp *= decay; self.fp *= decay
        self.fn *= decay
        if pred == 1 and label == 1:
            self.tp += self.alpha
        elif pred == 1 and label == 0:
            self.fp += self.alpha
        elif pred == 0 and label == 1:
            self.fn += self.alpha

    @property
    def f1(self):
        p = self.tp / (self.tp + self.fp + 1e-8)
        r = self.tp / (self.tp + self.fn + 1e-8)
        return 2 * p * r / (p + r + 1e-8)

